1	package com.fortinet.nac.ingestion.consumer.handler;
2	
3	import com.fortinet.nac.common.Constants;
4	import com.fortinet.nac.common.dto.IngestionRequest;
5	import com.fortinet.nac.common.util.StatusOr;
6	import com.fortinet.nac.ingestion.consumer.statemachine.EntityStateMachine;
7	import com.fortinet.nac.ingestion.consumer.handler.interfaces.FingerprintHandler;
8	import com.fortinet.nac.ingestion.entity.Entity;
9	import com.fortinet.nac.common.enums.EntityStage;
10	import com.fortinet.nac.ingestion.job.event.EntityResetEvent;
11	import com.fortinet.nac.ingestion.service.EntityService;
12	
13	import lombok.RequiredArgsConstructor;
14	import lombok.extern.slf4j.Slf4j;
15	import org.springframework.context.ApplicationEventPublisher;
16	import org.springframework.stereotype.Component;
17	
18	@Slf4j
19	@Component
20	@RequiredArgsConstructor
21	public class DifferentAttributesWithLockAcquiredHandler implements FingerprintHandler {
22	
23	    private final EntityService entityService;
24	    private final EntityStateMachine stateMachine;
25	    private final ApplicationEventPublisher eventPublisher;
26	
27	    @Override
28	    public StatusOr<Entity> handle(IngestionRequest req, Entity e, String reqFp) {
29	
30	        log.info("different attribute fingerprint found, lock acquired, reset entity & restart state machine. entityId={}",
31	                e.getId());
32	
33	        e.setAttributeFingerprint(reqFp);
34	        e.setProcessingStage(EntityStage.PENDING.toString());
35	        e.setProcessingCode(0);
36	        e.setInterrupted(false);
37	        e.setLastReqVersion(req.getVersion());
38	        e.setProcessingResult("{}");
39	        e.setErrorMessage("");
40	
41	        boolean ok = entityService.updateProcessingState(e);
42	        if (!ok) {
43	            log.error("Failed to reset processing state, entityId={}", e.getId());
44	            return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_DB_PROCESSING_STATE_UPDATE_FAILED,
45	                    "failed to reset processing state");
46	        }
47	
48	        eventPublisher.publishEvent(new EntityResetEvent(e.getId()));
49	
50	        return stateMachine.start(req.getRequestId(), req.isAsync(), e);
51	    }
52	}
