9	import reactor.netty.http.client.HttpClient;
10	
11	import java.time.Duration;
12	
13	@Configuration
14	public class PolicyNotificationConfig {
15	
16	    @Value("${policy.service.connect-timeout-ms:100}")
17	    private int connectTimeoutMs;
18	
19	    @Value("${policy.service.read-timeout-ms:200}")
