1	package com.fortinet.nac.ingestion.client;
2	
3	import lombok.extern.slf4j.Slf4j;
4	import org.springframework.beans.factory.annotation.Qualifier;
5	import org.springframework.beans.factory.annotation.Value;
6	import org.springframework.http.MediaType;
7	import org.springframework.stereotype.Component;
8	import org.springframework.web.reactive.function.client.WebClient;
9	
10	import java.util.Map;
11	
12	@Slf4j
13	@Component
14	public class PolicyNotificationClient {
15	
16	    private final WebClient webClient;
17	    private final String notificationUrl;
18	
19	    public PolicyNotificationClient(
20	            @Qualifier("policyNotificationWebClient") WebClient webClient,
21	            @Value("${policy.service.notification-url}") String notificationUrl) {
22	        this.webClient = webClient;
23	        this.notificationUrl = notificationUrl;
24	    }
25	
26	    // Fire-and-forget: .subscribe() returns immediately; HTTP I/O runs on Netty event loop.
27	    // Failures are best-effort — logged at WARN, never propagated to the caller.
28	    public void notifyEntityReset(long entityId) {
29	        webClient.post()
30	                .uri(notificationUrl)
31	                .contentType(MediaType.APPLICATION_JSON)
32	                .bodyValue(Map.of("entityId", entityId))
33	                .retrieve()
34	                .toBodilessEntity()
35	                .subscribe(
36	                        resp -> log.debug("policy reset notification sent, entityId={}, status={}", entityId, resp.getStatusCode()),
37	                        err -> log.warn("policy reset notification failed (best-effort), entityId={}, error={}", entityId, err.getMessage())
38	                );
39	    }
40	}
