1	package com.fortinet.nac.ingestion.consumer.handler;
2	
3	import com.fortinet.nac.common.Constants;
4	import com.fortinet.nac.common.dto.IngestionRequest;
5	import com.fortinet.nac.common.redis.DistributedLock;
6	import com.fortinet.nac.common.service.IdService;
7	import com.fortinet.nac.common.util.StatusOr;
8	import com.fortinet.nac.ingestion.consumer.FingerprintBuildResult;
9	import com.fortinet.nac.ingestion.consumer.statemachine.EntityStateMachine;
10	import com.fortinet.nac.ingestion.consumer.EntityAttributeFingerprintBuilder;
11	
12	import com.fortinet.nac.ingestion.delayqueue.RedisDelayQueueUtil;
13	import com.fortinet.nac.ingestion.entity.Entity;
14	import com.fortinet.nac.common.enums.EntityStage;
15	import com.fortinet.nac.common.enums.EntityType;
16	import com.fortinet.nac.ingestion.service.EntityService;
17	import com.fortinet.nac.ingestion.util.EntityCache;
18	import com.fortinet.nac.ingestion.util.RedisUtil;
19	
20	import lombok.RequiredArgsConstructor;
21	import lombok.extern.slf4j.Slf4j;
22	import org.springframework.beans.factory.annotation.Qualifier;
23	import org.springframework.stereotype.Component;
24	
25	import java.time.Instant;
26	
27	@Slf4j
28	@Component
29	@RequiredArgsConstructor
30	public class NewEntityHandler {
31	
32	    private final EntityService entityService;
33	    private final EntityCache entityCache;
34	    private final DistributedLock distributedLock;
35	    private final EntityStateMachine stateMachine;
36	    private final EntityAttributeFingerprintBuilder entityAttributeFingerprintBuilder;
37	
38	    @Qualifier("IngestionIdService")
39	    private final IdService idService;
40	
41	    private final RedisDelayQueueUtil redisDelayQueueUtil;
42	
43	    private static final int MAX_REQUEUE = 5;
44	
45	    public StatusOr<Entity> handle(IngestionRequest req) {
46	        // 1. build fingerprint
47	        FingerprintBuildResult fpResult = entityAttributeFingerprintBuilder.build(req);
48	        StatusOr<Void> validation = validateRefExists(req, fpResult);
49	        if (!validation.ok()) {
50	            return StatusOr.error(validation.getStatus().getCode(), validation.getStatus().getMessage());
51	        }
52	
53	        String fp = fpResult.getFingerprint();
54	
55	        // 2. create new entity
56	        Instant now = Instant.now();
57	
58	        Entity entity = Entity.builder()
59	                .id(idService.nextId())
60	                .type(EntityType.valueOf(req.getEntityType()))
61	                .source(req.getSource())
62	                .userId(req.getUserId())
63	                .hostId(req.getHostId())
64	                .adapterId(req.getAdapterId())
65	                .userIdentity(buildUserIdentity(req))
66	                .hostIdentity(buildHostIdentity(req))
67	                .processingStage(EntityStage.PENDING.toString())
68	                .processingCode(0)
69	                .attributeFingerprint(fp)
70	                .lastReqVersion(req.getVersion())
71	                .interrupted(false)
72	                .createdAt(now)
73	                .updatedAt(now)
74	                .build();
75	
76	        entityService.save(entity);
77	        log.info("Entity DB data created");
78	
79	        // 3. cache entityId
80	        String key = RedisUtil.getExistKey(req);
81	        try {
82	            // DB is the source of truth; the cache is used only for performance optimization.
83	            // Cache write failures should not fail the entire ingestion flow.
84	            entityCache.cacheEntityId(key, entity.getId(), Constants.RedisKeys.ENTITY_EXIST_KEY_TTL);
85	        } catch (Exception ex) {
86	            log.warn("Failed to cache entityId, degrade to DB lookup next time. key={}, entityId={}, err={}",
87	                     key, entity.getId(), ex.toString());
88	        }
89	
90	        // 4. acquire processLock
91	        String processLockKey = RedisUtil.getEntityLockKey(Constants.RedisKeys.ENTITY_PROCESS_LOCK_PREFIX, req);
92	        // Immediately after entity is created, another request may already
93	        // be processing the same entity (e.g., due to a cache hit and winning the processLock).
94	        StatusOr<String> lock = acquireProcessLockOrRequeue(req, entity.getId(), processLockKey);
95	        if (!lock.ok()) return StatusOr.error(lock.getStatus().getCode(), lock.getStatus().getMessage());
96	
97	        try {
98	            return stateMachine.start(req.getRequestId(), req.isAsync(), entity);
99	        } finally {
100	            distributedLock.unLock(processLockKey);
101	        }
102	    }
103	
104	    private StatusOr<String> acquireProcessLockOrRequeue(IngestionRequest req, long entityId, String processLockKey) {
105	        // quick retry in 1~2s
106	        boolean acquired = false;
107	        for (int i = 0; i < 10; i++) {
108	            acquired = distributedLock.tryLock(processLockKey, Constants.RedisKeys.ENTITY_PROCESS_LOCK_TTL);
109	            if (acquired) return StatusOr.ok(processLockKey);
110	            sleep(150);
111	        }
112	
113	        // requeue, due to acquire process lock failed
114	        log.warn("Cannot obtain processLock after creating db entity, begin requeue. entityId={}, key={}", entityId, processLockKey);
115	
116	        int retryCount = req.getRequeueCount();
117	        if (retryCount >= MAX_REQUEUE) {
118	            return StatusOr.error(Constants.BusinesCode.ACQUIRE_PROCESS_LOCK_FAILURE_AFTER_ENTITY_CREATED,
119	                    "process lock fail after create, exceeded max retry");
120	        }
121	
122	        long delaySeconds = 2L << retryCount;
123	        req.setRequeueCount(retryCount + 1);
124	
125	        try {
126	            redisDelayQueueUtil.enqueueWithDelay(req, delaySeconds * 1000);
127	        } catch (Exception ex) {
128	            log.error("Failed to enqueue delay queue, will retry via stream. entityId={}, err={}",
129	                    entityId, ex.toString());
130	            // INTERNAL_ERROR will trigger consumer retry
131	            return StatusOr.error(Constants.BusinesCode.INTERNAL_ERROR, "delay enqueue failed");
132	        }
133	
134	        return StatusOr.error(Constants.BusinesCode.ACQUIRE_PROCESS_LOCK_FAILURE_AFTER_ENTITY_CREATED,
135	                "process lock busy, request requeued");
136	    }
137	
138	    private String buildHostIdentity(IngestionRequest req) {
139	        return req.getHostId() + "_" + req.getAdapterId();
140	    }
141	
142	    private String buildUserIdentity(IngestionRequest req) {
143	        if (EntityType.USER_HOST_BINDING.toString().equals(req.getEntityType())) {
144	            return req.getUserId();
145	        }
146	        return null;
147	    }
148	
149	    void sleep(long ms) {
150	        try {
151	            Thread.sleep(ms);
152	        } catch (InterruptedException e) {
153	            Thread.currentThread().interrupt(); // restore interrupt flag
154	        }
155	    }
156	
157	    private StatusOr<Void> validateRefExists(IngestionRequest req, FingerprintBuildResult r) {
158	        EntityType type = EntityType.valueOf(req.getEntityType().toUpperCase());
159	
160	        String providedFp = req.getAttributeFingerprint();
161	        // 1. If a fingerprint is provided in request, skip validation of referenced entities
162	        if (providedFp != null && !providedFp.isBlank()) {
163	            return StatusOr.ok(null);
164	        }
165	
166	        // 2. Verify that the referenced entity exists in the database
167	        if (r.getHostAttribute() == null) {
168	            log.error(
169	                    "Validation failed: host not found. entityType={}, hostId={}, userId={}, adapterId={}, requestId={}",
