10	import com.fortinet.nac.ingestion.converter.EntityDTOConverter;
11	import com.fortinet.nac.ingestion.entity.Entity;
12	import com.fortinet.nac.common.enums.EntityProcessingCode;
13	import com.fortinet.nac.common.enums.EntityStage;
14	import com.fortinet.nac.common.failpoint.Failpoint;
15	import com.fortinet.nac.ingestion.registry.EntityProcessingRegistry;
16	import com.fortinet.nac.ingestion.service.EntityService;
17	
18	import io.micrometer.core.instrument.MeterRegistry;
19	import io.micrometer.core.instrument.Timer;
20	import lombok.RequiredArgsConstructor;
21	import lombok.extern.slf4j.Slf4j;
22	import org.springframework.stereotype.Component;
23	
24	import java.util.concurrent.*;
25	import java.util.function.Function;
26	
27	@Slf4j
28	@Component
29	@RequiredArgsConstructor
30	public class EntityStateMachine {
31	    private final EntityProcessingRegistry processingRegistry;
32	    private final EntityService entityService;
33	    private final ObjectMapper objectMapper;
34	    private final MeterRegistry meterRegistry;
35	    private final EntityDTOConverter entityDTOConverter;
36	
37	    private final EntityStageTransactionRunner txRunner;
38	
39	    public StatusOr<Entity> start(String requestId, boolean isAsync, Entity entity) {
40	        Timer.Sample sample = Timer.start(meterRegistry);
41	        long startTime = System.nanoTime();
42	        Long entityId = entity.getId();
43	
44	        EntityDTO entityDTO = entityDTOConverter.fromEntity(entity);
45	
46	        String resultTag = "success";
47	
48	        try {
49	            // Register current request context
50	            if (!isAsync) {
51	                processingRegistry.register(entityId, requestId);
52	            }
53	
54	            while (true) {
55	                if (entityService.isInterrupted(entityId)) {
56	                    log.info("Entity {} processing interrupted.", entityId);
57	
58	                    resultTag = "interrupted";
59	                    return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_PROCESS_INTERRUPTED, "interrupted");
60	                }
61	
62	                String stageStr = entityDTO.getProcessingStage();
63	                if (stageStr == null) {
64	                    resultTag = "fail";
65	                    return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_INVALID_ENTITY_STAGE,
66	                            "processingStage is null for entityId=" + entityId);
67	                }
68	
69	                EntityStage stage = EntityStage.valueOf(stageStr.toUpperCase());
70	
71	                int code = entityDTO.getProcessingCode() == null ? 0 : entityDTO.getProcessingCode();
72	                if (code != 0) {
73	                    log.info("Entity {} failed in stage={}, code={}", entityId, stage, code);
74	
75	                    resultTag = "fail";
76	                    return StatusOr.ok(entityDTOConverter.toEntity(entityDTO));
77	                }
78	
79	                boolean success = false;
80	
81	                switch (stage) {
82	                    case PENDING:
83	                        success = handlePending(entityDTO);
84	                        break;
85	                    case LABELED:
86	                        success = handleLabeled(entityDTO);
87	                        break;
88	                    case EVALUATED:
89	                        success = handleEvaluated(entityDTO);
90	                        break;
91	                    case ENFORCED:
92	                        // completed
93	                        return StatusOr.ok(entityDTOConverter.toEntity(entityDTO));
94	                    default:
95	                        resultTag = "fail";
96	                        return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_INVALID_ENTITY_STAGE,
97	                                "Invalid stage: " + stage);
98	                }
99	
100	                if (!success) {

100	                if (!success) {
101	                    resultTag = "fail";
102	                    return StatusOr.ok(entityDTOConverter.toEntity(entityDTO));
103	                }
104	            }
105	        } finally {
106	            if (!isAsync) {
107	                processingRegistry.unregister(entityId);
108	            }
109	            log.info("State Machine cost {} ms", TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startTime));
110	
111	            String stageStr = entityDTO.getProcessingStage();
112	            String finalStageTag = (stageStr == null ? "UNKNOWN" : stageStr.toUpperCase());
113	
114	            Timer timer = Timer.builder("ingestion_state_machine_seconds")
115	                    .tag("result", resultTag)
116	                    .tag("finalStage", finalStageTag)
117	                    .register(meterRegistry);
118	            sample.stop(timer);
119	        }
120	    }
121	
122	    /**
123	     * PENDING stage: call labelService
124	     */
125	    private boolean handlePending(EntityDTO dto) {
126	        return processStage(dto, EntityStage.LABELED, txRunner::runLabel);
127	    }
128	
129	    /**
130	     * LABELED stage: call PolicyService
131	     */
132	    private boolean handleLabeled(EntityDTO dto) {
133	        return processStage(dto, EntityStage.EVALUATED, txRunner::runPolicy);
134	    }
135	
136	    /**
137	     * EVALUATED stage: call EnforcementService
138	     */
139	    private boolean handleEvaluated(EntityDTO dto) {
140	        return processStage(dto, EntityStage.ENFORCED, txRunner::runEnforce);
141	    }
142	
143	
144	    private boolean processStage(
145	            EntityDTO dto,
146	            EntityStage nextStageEnum,
147	            Function<EntityDTO, ObjectNode> serviceFunction
148	    ) {
149	        long entityId = dto.getId();
150	        String currentStage = dto.getProcessingStage();
151	        String nextStage = nextStageEnum.toString();
152	
153	        log.info("StateMachine: [{} -> {}] START, entityId={}",
154	                currentStage, nextStage, entityId);
155	
156	        final int MAX_RETRY = 3;
157	
158	        boolean serviceSuccess = false;
159	
160	        for (int attempt = 1; attempt <= MAX_RETRY; attempt++) {
161	            log.info("Executing [{}] service, attempt={}, entityId={}",
162	                    nextStage, attempt, entityId);
163	
164	            // Failpoint 1: crash before invoking downstream services
165	            Failpoint.crashIfEnabled(Constants.Failpoints.SM_BEFORE_SERVICE_PREFIX + nextStage);
166	
167	            ObjectNode serviceResult = serviceFunction.apply(dto);
168	
169	            // Failpoint 2: crash after service returns but before updating DTO/DB
170	            Failpoint.crashIfEnabled(Constants.Failpoints.SM_AFTER_SERVICE_PREFIX + nextStage);
171	
172	            if (serviceResult == null) {
173	                serviceResult = objectMapper.createObjectNode();
174	                serviceResult.put("code", -1);
175	                serviceResult.put("errMessage", "null serviceResult");
176	            }
177	
178	            int code = serviceResult.path("code").asInt();
179	            if (code == 0) {
180	                serviceSuccess = true;
181	                handleServiceSuccess(dto, nextStage, serviceResult, attempt);
182	                break;
183	            }
184	
185	            log.warn("Stage [{}] returned non-zero code on attempt {}: code={}, err={}, entityId={}",
186	                    nextStage, attempt, code, serviceResult.path("errMessage").asText(), entityId);
187	
188	            boolean retryable = EntityProcessingCode.isRetryableCode(nextStageEnum, code);
189	            if (!retryable) {
190	                // Non-retryable; current attempt is the final failure
191	                handleServiceFinalFailure(dto, nextStage, serviceResult, attempt, false);
192	                break;
193	            }
194	            if (attempt == MAX_RETRY) {
195	                // Retryable but exhausted max attempts
196	                handleServiceFinalFailure(dto, nextStage, serviceResult, attempt, true);
197	                break;
198	            }
199	
200	            long base = 1000L * attempt;
201	            // avoid Thundering Herd: prevent many requests retrying at the same time
202	            long jitter = ThreadLocalRandom.current().nextLong(0, 100); // 0~99ms
203	            long sleepMs = base + jitter;
204	            log.info("Backoff {} ms before retrying stage [{}]...", sleepMs, nextStage);
205	            sleep(sleepMs);
206	        }
207	
208	        // update stage in DTO
209	        dto.setProcessingStage(nextStage);
210	        boolean dbSuccess = updateDBEntityProcessingState(dto);
211	
212	        return serviceSuccess && dbSuccess;
213	    }
214	
215	
216	    /**
217	     * Append each stage result into processingResult; real implementation may merge JSON objects
218	     */
219	    public void mergeProcessingResult(EntityDTO dto, String stageKey, JsonNode stageProcessingRes) {
220	        ObjectNode root = objectMapper.createObjectNode();
221	
222	        String existing = dto.getProcessingResult();
223	        if (existing != null && !existing.isEmpty()) {
224	            try {
225	                root = (ObjectNode) objectMapper.readTree(existing);
226	            } catch (Exception e) {
227	                // Log only, do not throw, to avoid breaking the state machine
228	                log.error("mergeProcessingResult: invalid JSON in processingResult for entity {}, will overwrite. raw={}, err={}",
229	                        dto.getId(), existing, e.getMessage());
230	                // Keep raw content in a special field
231	                ObjectNode corrupt = objectMapper.createObjectNode();
232	                corrupt.put("raw", existing);
233	                root.set("_corruptProcessingResult", corrupt);
234	            }
235	        }
236	
237	        // avoid NPE
238	        if (stageProcessingRes == null) {
239	            root.putNull(stageKey);
240	        } else {
241	            root.set(stageKey, stageProcessingRes);
242	        }
243	
244	        dto.setProcessingResult(root.toString());
245	    }
246	
247	
248	    // just update entity in memory (DTO)
249	    private void handleServiceSuccess(EntityDTO dto, String nextStage, ObjectNode serviceResult, int attempt) {
250	        mergeProcessingResult(dto, nextStage, serviceResult.path("data"));
251	        dto.setProcessingCode(0);
252	        dto.setErrorMessage(null);
253	
254	        log.info("Stage [{}] SUCCESS on attempt {}, entityId={}",
255	                nextStage, attempt, dto.getId());
256	    }
257	
258	    // just update entity in memory (DTO)
259	    private void handleServiceFinalFailure(EntityDTO dto, String nextStage,
260	                                           ObjectNode serviceResult, int attempt,
261	                                           boolean exhaustedRetry) {
262	        int code = serviceResult.path("code").asInt(-1);
263	        dto.setProcessingCode(code);
264	
265	        String msg = serviceResult.path("errMessage").asText(null);
266	        dto.setErrorMessage(msg);
267	
268	        ObjectNode err = objectMapper.createObjectNode();
269	        err.put("error", msg == null ? "unknown error" : msg);
270	        err.put("attempt", attempt);
271	        err.put("exhaustedRetry", exhaustedRetry);
272	        mergeProcessingResult(dto, nextStage, err);
273	
274	        if (exhaustedRetry) {
275	            log.error("Stage [{}] FAILED after exhausting retries, attempts={}, entityId={}, code={}, error={}",
276	                    nextStage, attempt, dto.getId(), code, msg);
277	        } else {
278	            log.error("Stage [{}] FAILED with non-retryable code, attempt={}, entityId={}, code={}, error={}",
279	                    nextStage, attempt, dto.getId(), code, msg);
280	        }
281	    }
282	
283	
284	    private boolean updateDBEntityProcessingState(EntityDTO dto) {
285	        Entity entity = entityDTOConverter.toEntity(dto);
286	        boolean ok = entityService.updateProcessingState(entity);
287	        if (!ok) {
288	            log.error("DB update FAILED (rows=0), stage={}, entityId={}",
289	                      dto.getProcessingStage(), dto.getId());
290	            return false;
291	        }
292	
293	        log.info("StateMachine: [{}] DB updated, entityId={}", dto.getProcessingStage(), dto.getId());
294	        return true;
295	    }
296	
297	    private void sleep(long ms) {
298	        try {
299	            Thread.sleep(ms);
300	        } catch (InterruptedException ignored) {
301	            Thread.currentThread().interrupt();
302	        }
303	    }
304	
305	    // only used for tolerance testing
306	    private void simulateDelay(int minMs, int maxMs) {
307	        int delay = ThreadLocalRandom.current().nextInt(minMs, maxMs + 1);
308	        try {
309	            Thread.sleep(delay);
310	        } catch (InterruptedException e) {
311	            Thread.currentThread().interrupt();
312	            throw new RuntimeException("Interrupted during simulated delay", e);
313	        }
314	    }
315	}
