@Component
public class PolicyNotificationClient {

    private final WebClient webClient;
    private final String notificationUrl;

    public PolicyNotificationClient(
            @Qualifier("policyNotificationWebClient") WebClient webClient,
            @Value("${policy.service.notification-url}") String notificationUrl) {
        this.webClient = webClient;
        this.notificationUrl = notificationUrl;
    }

    public void notifyEntityReset(long entityId) {
        webClient.post()
                .uri(notificationUrl)
                .contentType(MediaType.APPLICATION_JSON)
                .bodyValue(Map.of("entityId", entityId))
                .retrieve()
                .toBodilessEntity()
                .subscribe(
                        resp -> log.debug("policy reset notification sent, entityId={}, status={}", entityId, resp.getStatusCode()),
                        err -> log.warn("policy reset notification failed (best-effort), entityId={}, error={}", entityId, err.getMessage())
                );
    }
}
